local http = require "resty.http"

local function is_valid_url(url)
    -- Basic validation to ensure the URL is well-formed
    return url:match("^(http://[%w%.%-]+:%d+.*)$") or url:match("^(https://[%w%.%-]+:%d+.*)$")
end

local function is_internal_address(url)
    -- Check for internal addresses (e.g., localhost, private IP ranges)
    local internal_patterns = {
        "127%.0%.0%.1", -- localhost
        "^10%.",        -- 10.0.0.0/8
        "^172%." .. "([1][6-9]|[2][0-9])%.", -- 172.16.0.0/12
        "^192%.168%.",  -- 192.168.0.0/16
        "^::1$",        -- IPv6 localhost
        "^fc00:",       -- Unique local addresses (ULA)
        "^fe80:",       -- Link-local addresses
    }
    for _, pattern in ipairs(internal_patterns) do
        if url:match(pattern) then
            return true
        end
    end
    return false
end

local url = ngx.var.arg_url

if not url or not is_valid_url(url) or is_internal_address(url) then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Invalid URL")
